local LxResRequester = require("LApp.resource.LxResRequester")
local LxAssetData = require("LApp.resource.LxAssetData")
local XAssetFinder = PJX.XAssetFinder
local AssetLoadType = AssetLoadType
local Time = Time
local xpcallX = xpcallX
local PJXGameMgr = PJXCenter.GameMgr

local RegularAssetPath = function(path)
    if string.startswith(path, "Packages/com.unity") then
        return path
    end
    if string.startswith(path, "Assets/Res/") then
        return path
    end
    return "Assets/Res/" .. path
end



function LxResourceMgr:Initialize()
    LxBaseMgr.Initialize(self)

    self._keepLuaGCCount = 0
    self._keepLuaGCAccCount = nil
    self._luaCleanLimitCount = 35480
    self._luaFrameChangeLimitCount = 254800

    self._nextFreeGCTime = nil
    self._freeGCInterval = LGameSettings.clearBundleInterval or 120
    self._isUnloading = false

    ---@type table<number, Material>
    self._materials = {}

    ---@type LxVersion
    self._activeAppVersion = nil
    ---@type LxVersion
    self._activePackageVersion = nil
    ---@type LxVersion
    self._builtinAppVersion = nil
    ---@type LxVersion
    self._builtinPackageVersion = nil

    ---@type table<string,LxAssetData>
    self._assetMap = {}
    ---@type table<string,LxAssetData>
    self._allAssetsMap = {}
    ---@type table<string,LxAssetData>
    self._subAssetsMap = {}
    ---@type table<string,LxAssetData>
    self._sceneMap = {}
    ---@type table<string,LxAssetData>
    self._handleMap = {}

    ---@type LxAssetData[]
    self._releaseList = {}

    self._doneList = {}

    self._loadAssetDoneFunc = function(handle)
        self:_OnLoadAssetDone(handle)
    end
    self._loadAllAssetsDoneFunc = function(handle)
        self:_OnLoadAssetDone(handle)
    end
    self._loadSubAssetsDoneFunc = function(handle)
        self:_OnLoadAssetDone(handle)
    end
    self._loadSceneDoneFunc = function(handle)
        self:_OnLoadAssetDone(handle)
    end
    self._loadRawFileDoneFunc = function(handle)
        self:_OnLoadAssetDone(handle)
    end

    self:InitRequester()
end

function LxResourceMgr:Dispose()
    if self._isDisposed then return end

    table.dispose(self._materials)
    self:ClearAllAssets()
    LxBaseMgr.Dispose(self)
end

