function LxResourceMgr:ClearAllRequester()
    if LOG_INFO_ENABLED then
        self:LogRequesterStatus()
    end

    local requesterMap = self._requesterMap
    self._requesterMap = nil

    for k,v in pairs(requesterMap) do
        v:Dispose()
    end
    self._requesterMap = {}
end

---热更lua 后热重载 调用
function LxResourceMgr:ClearAllAssets()
    self:ClearAllRequester()

    for k,v in pairs(self._handleMap) do
        self:_ClearAssetData(v)
    end

    self._handleMap = {}

    self._assetMap = {}
    self._allAssetsMap = {}
    self._subAssetsMap = {}

    self._sceneMap = {}

    self._doneList = {}

    self._releaseList = {}

    XAssetFinder.ClearAllScene()
end

function LxResourceMgr:OnUpdate()
    if self._isDisposed then return end

    local doneList = self._doneList
    if #doneList > 0 then
        local len = #doneList
        for k=len, 1,-1 do
            local handle = doneList[k]
            table.remove(doneList, k)
            if not handle then
                break
            end
            self:_InvokeHandleDone(handle)
        end
    end

    local releaseList = self._releaseList
    if #releaseList > 0 then
        local time = Time.realtimeSinceStartup
        local releaseLen = #releaseList
        for k = releaseLen, 1, - 1 do
            local data = releaseList[k]
            if data:IsDispose() then
                --已经被删了，直接移除出检查列表
                table.remove(releaseList, k)
            elseif data.refCount > 0 then
                --又有引用了，改变状态， 移除出检查列表
                data.releasing = false
                table.remove(releaseList, k)
            elseif data:IsReachFreeTime(time) then
                --够时间删了， 移除
                self:_ClearAssetDataAndContainer(data)
                table.remove(releaseList, k)
            end
        end
    end
end

---@param data LxAssetData
function LxResourceMgr:AddReleasing(data)
    data.releasing = true
    table.insert(self._releaseList, data)
end

---@param data LxAssetData
function LxResourceMgr:_ClearAssetDataAndContainer(data)
    self._handleMap[data.handle] = nil
    local loadType = data.loadType
    if loadType == AssetLoadType.Asset then
        self._assetMap[data.assetPath] = nil
    elseif loadType == AssetLoadType.AllAssets then
        self._allAssetsMap[data.assetPath] = nil
    elseif loadType == AssetLoadType.SubAssets then
        self._subAssetsMap[data.assetPath] = nil
    elseif loadType == AssetLoadType.Scene then
        self._sceneMap[data.assetPath] = nil
    elseif loadType == AssetLoadType.RawFile then

    end
    self:_ClearAssetData(data)
end

---@param data LxAssetData
function LxResourceMgr:_ClearAssetData(data)
    data:Dispose()
end

function LxResourceMgr:_OnLoadAssetDone(handle)
    local assetData = self._handleMap[handle]
    if not handle then return end

    local proxy = handle.Proxy
    if not proxy then return end

    assetData.IsDone = true
    table.insert(self._doneList, handle)
    local loadType = assetData.loadType
    if loadType == AssetLoadType.Asset then
        assetData.asset = proxy.AssetObject
    elseif loadType == AssetLoadType.AllAssets then
        assetData.asset = proxy.AllAssetObjects
    elseif loadType == AssetLoadType.SubAssets then
        assetData.asset = proxy.AllAssetObjects
    elseif loadType == AssetLoadType.Scene then
        assetData.asset = proxy.SceneObject
    elseif loadType == AssetLoadType.RawFile then
        assetData.asset = proxy.RawFilePath
    end
end

function LxResourceMgr:_InvokeHandleDone(handle)
    local assetData = self._handleMap[handle]
    if not assetData then return end

    local asset = assetData.asset
    if LOG_INFO_ENABLED then
        if not asset then
            printError("ResourceMgr","asset cannot load, path=%s, type=%s" , assetData.assetPath, tostring(assetData.assetType))
        end
    end
    local requesterList = assetData.requesterList
    assetData.requesterList = nil
    if not requesterList then return end

    for k,requester in ipairs(requesterList) do
        if self._isDisposed then break end

        self:_InvokeRequesterComplete(requester)
    end
end

---@param requester LxResRequester
function LxResourceMgr:_InvokeRequesterComplete(requester)
    if requester == nil then return end

    xpcallX(requester.InvokeComplete, requester)
end

---@param requester LxResRequester
function LxResourceMgr:_CheckAssetLoad(assetPath, assetType, requester, dataMap)
    local assetData = dataMap[assetPath]
    if not assetData then return false end

    local handle = assetData.handle
    if handle.IsValid then
        requester:SetAssetData(assetData)
        if assetData.IsDone then
            self:_InvokeRequesterComplete(requester)
        else
            local index = table.indexof(assetData.requesterList, requester)
            if index then
                table.remove(assetData.requesterList, index)
            end
            table.insert(assetData.requesterList, requester)
        end
        return true
    end

    dataMap[assetPath] = nil
    self._handleMap[handle] = nil
    self:_ClearAssetData(assetData)
    return false
end

---@param requester LxResRequester
---@return LxAssetData
function LxResourceMgr:_RecordData(handle, loadType, assetPath, assetType, requester)
    local requesterList = nil
    if requester ~= nil then
        requesterList =  {requester}
    end
    local assetData = LxAssetData:New()
    assetData:Initialize(handle, loadType, assetType, assetPath, requesterList)
    self._handleMap[handle] = assetData
    requester:SetAssetData(assetData)
    return assetData
end

---@region 资源加载
function LxResourceMgr:LoadAssetAsync(assetPath, assetType, requester)
    if string.isempty(assetPath) then
        self:_InvokeRequesterComplete(requester)
        return
    end

    local validPath = RegularAssetPath(assetPath)
    if self:_CheckAssetLoad(validPath, assetType, requester, self._assetMap) then return end

    local handle = XAssetFinder.LoadAssetAsync(validPath, assetType)
    local assetData = self:_RecordData(handle, AssetLoadType.Asset, validPath, assetType, requester)
    self._assetMap[validPath] = assetData
    assetData.func = self._loadAssetDoneFunc
    handle.OnCompletedCallback = self._loadAssetDoneFunc
    if handle.IsDone then
        self._loadAssetDoneFunc(handle)
    end
end

function LxResourceMgr:LoadAllAssetsAsync(assetPath, assetType, requester)
    if string.isempty(assetPath) then
        self:_InvokeRequesterComplete(requester)
        return
    end

    local validPath = RegularAssetPath(assetPath)
    if self:_CheckAssetLoad(validPath, assetType, requester, self._allAssetsMap) then return end

    local handle = XAssetFinder.LoadAllAssetsAsync(validPath, assetType)
    local assetData = self:_RecordData(handle, AssetLoadType.AllAssets, validPath, assetType, requester)
    self._allAssetsMap[validPath] = assetData
    assetData.func = self._loadAllAssetsDoneFunc
    handle.OnCompletedCallback = self._loadAllAssetsDoneFunc
    if handle.IsDone then
        self._loadAllAssetsDoneFunc(handle)
    end
end

function LxResourceMgr:LoadSubAssetsAsync(assetPath, assetType, requester)
    if string.isempty(assetPath) then
        self:_InvokeRequesterComplete(requester)
        return
    end

    local validPath = RegularAssetPath(assetPath)
    if self:_CheckAssetLoad(validPath, assetType, requester, self._subAssetsMap) then return end

    local handle = XAssetFinder.LoadSubAssetsAsync(validPath, assetType)
    local assetData = self:_RecordData(handle, AssetLoadType.SubAssets, validPath, assetType, requester)
    self._subAssetsMap[validPath] = assetData
    assetData.func = self._loadSubAssetsDoneFunc
