function LxResourceMgr:LoadSceneAsync(assetPath, loadSceneMode, suspendLoad, priority, requester)
    if string.isempty(assetPath) then
        self:_InvokeRequesterComplete(requester)
        return
    end
    local validPath = RegularAssetPath(assetPath)
    if self:_CheckAssetLoad(validPath, nil, requester, self._sceneMap) then return end

    local handle = XAssetFinder.LoadSceneAsync(validPath, loadSceneMode, suspendLoad, priority)
    local assetData = self:_RecordData(handle, AssetLoadType.Scene, validPath, nil, requester)
    self._sceneMap[validPath] = assetData
    assetData.func = self._loadSceneDoneFunc
    handle.OnCompletedCallback = self._loadSceneDoneFunc
    if handle.IsDone then
        self._loadSceneDoneFunc(handle)
    end
end

function LxResourceMgr:LoadRawFileAsync(assetPath, assetType, requester)
    LogError("LoadRawFileAsync not implementation")
end
---@endregion 对外接口 资源加载

---@region 场景资源释放
function LxResourceMgr:UnloadAllScene()
    local bHave = false
    for k,v in pairs(self._sceneMap) do
        self._handleMap[v.handle] = nil
        self:_ClearAssetData(v)
        self._sceneMap[k] = nil
        bHave = true
    end
    if bHave then
        XAssetFinder.ClearAllScene()
    end
end
---@endregion 场景资源释放

---@region 版本信息
function LxResourceMgr:InitVersions()
    local defaultAppVersion = LxResUtil.ConvertToVersion(PJX.AppConst.DefaultAppVersion)
    local defaultPackageVersion = LxResUtil.ConvertToVersion(PJX.AppConst.DefaultPackageVersion)

    self._activeAppVersion = defaultAppVersion
    self._activePackageVersion = defaultPackageVersion

    local versionFile = XAssetFinder.ActiveVersionFile
    if versionFile then
        self._activeAppVersion = LxResUtil.ConvertToVersion(versionFile.AppVersion)
        self._activePackageVersion = LxResUtil.ConvertToVersion(versionFile.PackageVersion)
    end

    self._builtinAppVersion = defaultAppVersion
    self._builtinPackageVersion = defaultPackageVersion
    versionFile = XAssetFinder.BuiltinVersionFile
    if versionFile then
        self._builtinAppVersion = LxResUtil.ConvertToVersion(versionFile.AppVersion)
        self._builtinPackageVersion = LxResUtil.ConvertToVersion(versionFile.PackageVersion)
    end
end

function LxResourceMgr:GetBuiltinVersions()
    return self._builtinAppVersion, self._builtinPackageVersion
end

function LxResourceMgr:GetActiveVersions()
    return self._activeAppVersion, self._activePackageVersion
end
---@endregion 版本信息

