---@region 材质球
function LxResourceMgr:InitMaterial(mat, materialType)
    if not self._materials then return end

    if self._materials[materialType] then return end

    self._materials[materialType] = mat
end

function LxResourceMgr:GetMaterial(materialType)
    return self._materials and self._materials[materialType] or nil
end

