---@region 资源请求处理
function LxResourceMgr:InitRequester()
    local idList = {}
    ---当前正在使用的资源量按照道理是不会超过1000的，这里设置2000
    ---如果还发生不够的现在，确定为回收机制出了问题
    for k = 1, 2000 do
        table.insert(idList, k)
    end

    self._freeRequesterIds = idList
    self._maxRequesterId = 2000
    self._freeRequesterIdCount = 2000

    ---@type table<number, LxResRequester>
    self._requesterMap = {}
    self._requesterCount = 0
end

function LxResourceMgr:GetRequesterId()
    if self._freeRequesterIdCount > 0 then
        local id = table.remove(self._freeRequesterIds)
        self._freeRequesterIdCount = self._freeRequesterIdCount - 1
        return id
    else
        --能跑到这里应该是资源回收机制出了问题，此处加个防护机制
        --防止溢出
        if LOG_INFO_ENABLED then
            LogError("资源回收出现了严重问题，请检查是否未按照规定释放资源")
        end
        local id = self._maxRequesterId + 1
        self._maxRequesterId = id
        return id
    end
end

---@param requester LxResRequester
function LxResourceMgr:RemoveRequester(requester)
    if not self._requesterMap then return end
    
    local id = requester:GetId()
    if self._requesterMap[id] then
        self._requesterMap[id] = nil
        table.insert(self._freeRequesterIds, id)
        self._freeRequesterIdCount = self._freeRequesterIdCount + 1
    end
end

function LxResourceMgr:CreateAssetRequester(assetPath, assetType, callBack)
    local id = self:GetRequesterId()
    local requester = LxResRequester:New()
    requester:Initialize(id, AssetLoadType.Asset, assetPath, assetType, callBack)
    self._requesterMap[id] = requester
    return requester
end

function LxResourceMgr:CreateAllAssetsRequester(assetPath, assetType, callBack)
    local id = self:GetRequesterId()
    local requester = LxResRequester:New()
    requester:Initialize(id, AssetLoadType.AllAssets, assetPath, assetType, callBack)
    self._requesterMap[id] = requester
    return requester
end

function LxResourceMgr:CreateSubAssetsRequester(assetPath, assetType, callBack)
    local id = self:GetRequesterId()
    local requester = LxResRequester:New()
    requester:Initialize(id, AssetLoadType.SubAssets, assetPath, assetType, callBack)
    self._requesterMap[id] = requester
    return requester
