function LxResourceMgr:CreateSceneRequester(assetPath, loadSceneMode, suspendLoad, priority, callBack)
    local id = self:GetRequesterId()
    local requester = LxResRequester:New()
    requester:Initialize(id, AssetLoadType.Scene, assetPath, nil, callBack)
    requester:SetSceneModeParam(loadSceneMode, suspendLoad, priority)
    self._requesterMap[id] = requester
    return requester
end
---@endregion 资源请求处理

---@region 资源
function LxResourceMgr:RunUnusedAssetUnload()
    if self._isDisposed then return end

    if self._isUnloading then
        printInfo("ResourceMgr", string.format("--->>> 检测时， 释放标记 %s", tostring(self._isUnloading)))
        if self._nextFreeGCTime and Time.realtimeSinceStartup - self._nextFreeGCTime < 60 then
            --gc了超过三分钟就不返回了， 进行下一次GC
            return
        end
        self._isUnloading = false
    end

    if gLFightManager and gLFightManager:HasBattleInFront() then
        --战斗时不释放
        return
    end

    local unusedCount, total = LxResUtil.CalcUnusedAssetProxys()
    if LOG_INFO_ENABLED then
        printInfo("ResourceMgr", string.format("当前可释放proxy数量：%s， 总数量：%s", tostring(unusedCount), tostring(total)))
    end

    local isExecuteGC = false

    --使用适当的判断条件，减少调用unload的次数，降低游戏内切换场景的发热量
    if unusedCount > LGameSettings.clearBundleCount or total > LGameSettings.clearBundleTotalCount then
        --增加清理时间间隔
        local curTime = Time.realtimeSinceStartup
        local nextTime = self._nextFreeGCTime
        if not nextTime or nextTime <= curTime then
            isExecuteGC = true
            self._nextFreeGCTime = curTime + self._freeGCInterval
        end
    end

    if isExecuteGC then
        if LOG_INFO_ENABLED then
            printInfo("ResourceMgr", "满足清理资源条件，清理资源。")
        end
        self._isUnloading = true
        LxResUtil.UnloadUnusedAssets(function()
            self._isUnloading = false
            if LOG_INFO_ENABLED then
                unusedCount, total = LxResUtil.CalcUnusedAssetProxys()
                printInfo("ResourceMgr", string.format("--->>> 释放后， 释放标记 %s", tostring(self._isUnloading)))
                printInfo("ResourceMgr", string.format("--->>> 释放后， 当前可释放proxy数量：%s， 总数量：%s", tostring(unusedCount), tostring(total)))
            end
            PJXGameMgr:GameOnceGC()
        end)
    end
end

---lua gc
function LxResourceMgr:RunSimpleLuaGC()
    if self._keepLuaGCCount == nil then
        return
    end

    local old = self._keepLuaGCCount
    local newC = LxResUtil.LuaGCCount()

    local gap = newC - old
    if self._keepLuaGCAccCount ~= nil then
        self._keepLuaGCAccCount = self._keepLuaGCAccCount + gap
    else
        self._keepLuaGCAccCount = 0
    end
    if newC < self._luaFrameChangeLimitCount  then
        self._keepLuaGCCount = newC
        return
    end

    if self._keepLuaGCAccCount > self._luaCleanLimitCount then
        LxResUtil.InvokeLuaGC()
        self._keepLuaGCAccCount = nil
    end
    self._keepLuaGCCount = newC
end

---@endregion
return LxResourceMgr